import React, { forwardRef } from 'react';
import { Animated, Modal, ScrollView } from 'react-native';

import { useTheme } from 'styled-components/native';

import theme from '../../../styles/theme';

import normalize, {
  SCREEN_HEIGHT,
  SCREEN_WIDTH,
} from '../../constants/normalize';
import { isIos } from '../../constants/validations';
import { Box, TouchBox } from '../Box';
import useModalize from './index';
import { PropsModalize, propsModalizeRef } from './Models';

const Modalize = forwardRef(
  (
    {
      testID,
      pd = 'innerLarger',
      bgColor = 'INTENSE_COLOR_01',
      children,
      showHeaderHandle = true,
      enableDragUp = false,
      maxDrag,
      onClose,
      onDragging,
      onFinishDrag,
      hasDragDown = false,
      closeOnPressOutside = true,
      hasMarginBottom = true,
      disabled = false,
      height = 'auto',
      scrollEnabled = false,
      adjustToContentHeight = true,
      onBackButtonPress,
      HeaderComponent,
      disableMaxHeight = false,
      closeInstantly = false,
    }: PropsModalize,
    ref: propsModalizeRef,
  ) => {
    const { colors, borderRadius } = useTheme() || theme;
    const { visible, translateY, panResponder, onScroll } = useModalize({
      onDragging,
      onClose,
      ref,
      enableDragUp,
      maxDrag,
      onFinishDrag,
      hasDragDown,
      onBackButtonPress,
      closeInstantly,
    });

    return (
      <Modal visible={visible} transparent testID={testID}>
        <TouchBox
          width={SCREEN_WIDTH}
          testID="DS-Modalize-TouchBox"
          onPress={() => (closeOnPressOutside ? ref?.current.close() : null)}
          activeOpacity={1}
          disabled={disabled}
        >
          <Box
            height="100%"
            width="100%"
            opacity={0.5}
            position="absolute"
            bgColor="BRAND_COMPLEMENT_01"
          />
          <Box height="100%" justify="flex-end">
            <Animated.View
              testID="DS-Modalize-Animated-View"
              {...panResponder.panHandlers}
              style={{
                transform: [{ translateY: enableDragUp ? 0 : translateY }],
                width: SCREEN_WIDTH,
                overflow: 'hidden',
                height,
                maxHeight: (() => {
                  if (disableMaxHeight) return undefined;
                  if (height === 'auto' && adjustToContentHeight)
                    return SCREEN_HEIGHT - 80;
                  return height;
                })(),
                backgroundColor: colors[bgColor],
                borderTopLeftRadius: borderRadius?.half,
                borderTopRightRadius: borderRadius?.half,
              }}
            >
              {showHeaderHandle && (
                <Box
                  width={SCREEN_WIDTH}
                  align="center"
                  justify="center"
                  position="absolute"
                  mt="xxxxs"
                >
                  <Box
                    width={normalize(44)}
                    height={normalize(4)}
                    bgColor="INTENSE_COLOR_02"
                    br="small"
                  />
                </Box>
              )}

              {HeaderComponent && (
                <Box width="100%" index={0} mt="xs">
                  {HeaderComponent}
                </Box>
              )}

              {scrollEnabled ? (
                <ScrollView
                  style={{
                    width: '100%',
                  }}
                  onScroll={onScroll}
                  scrollEventThrottle={16}
                  scrollEnabled={scrollEnabled}
                  showsVerticalScrollIndicator={false}
                >
                  <TouchBox
                    width="100%"
                    height="100%"
                    align="center"
                    activeOpacity={1}
                    disabled={disabled}
                  >
                    <Box width="100%" pd={pd}>
                      {children}
                      {isIos() && hasMarginBottom && (
                        <Box mt="xs" width="100%" />
                      )}
                    </Box>
                  </TouchBox>
                </ScrollView>
              ) : (
                <TouchBox
                  width="100%"
                  align="center"
                  activeOpacity={1}
                  disabled={disabled}
                >
                  <Box width="100%" pd={pd}>
                    {children}
                    {isIos() && hasMarginBottom && <Box mt="xs" width="100%" />}
                  </Box>
                </TouchBox>
              )}
            </Animated.View>
          </Box>
        </TouchBox>
      </Modal>
    );
  },
);

export default Modalize;

