import { useEffect, useImperativeHandle, useRef, useState } from 'react';
import {
  Animated,
  PanResponder,
  Dimensions,
  PanResponderGestureState,
  GestureResponderEvent,
  NativeSyntheticEvent,
  NativeScrollEvent,
  BackHandler,
} from 'react-native';

import { propsUseModalize } from './Models';

export default function useModalize({
  onDragging,
  onFinishDrag,
  onClose,
  ref,
  enableDragUp,
  maxDrag = 0,
  hasDragDown,
  onBackButtonPress,
  shouldUseAbsoluteValue = true,
  closeInstantly,
}: propsUseModalize) {
  const translateY = useRef(
    new Animated.Value(Dimensions.get('window').height),
  ).current;
  const screenHeight = Dimensions.get('window').height;
  const [visible, setVisible] = useState(false);
  const [scrollIsAtTop, setScrollIsAtTop] = useState(true);
  const scrollIsAtTopRef = useRef(scrollIsAtTop);

  useImperativeHandle(ref, () => ({
    open: () => {
      setVisible(true);
      Animated.timing(translateY, {
        toValue: 0,
        duration: 300,
        useNativeDriver: true,
      }).start();
    },
    close: () => {
      Animated.timing(translateY, {
        toValue: screenHeight,
        duration: closeInstantly ? 0 : 300,
        useNativeDriver: true,
      }).start(() => {
        setVisible(false);
        if (onClose) onClose();
      });
    },
  }));

  const onScroll = (event: NativeSyntheticEvent<NativeScrollEvent>) => {
    const scrollPosition = event.nativeEvent.contentOffset.y;
    setScrollIsAtTop(scrollPosition <= 0);
  };

  const onMoveShouldSetPanResponder = (
    _: GestureResponderEvent,
    gestureState: PanResponderGestureState,
  ) => {
    return (
      scrollIsAtTopRef.current &&
      (shouldUseAbsoluteValue
        ? Math.abs(gestureState.dy) > 10
        : gestureState.dy > 10)
    );
  };

  const onStartShouldSetPanResponder = () => false;

  const onPanResponderMove = (
    _: GestureResponderEvent,
    gestureState: PanResponderGestureState,
  ) => {
    if (enableDragUp && maxDrag < gestureState.dy) {
      onDragging?.(gestureState);
      translateY.setValue(gestureState.dy);
    } else if (scrollIsAtTopRef.current && gestureState.dy > 0) {
      translateY.setValue(gestureState.dy);
    }
  };

  const onPanResponderRelease = (
    _: GestureResponderEvent,
    gestureState: PanResponderGestureState,
  ) => {
    if (!hasDragDown && gestureState.dy > 100) {
      ref?.current.close();
    } else {
      Animated.timing(translateY, {
        toValue: 0,
        duration: 200,
        useNativeDriver: true,
      }).start();
    }
    onFinishDrag?.(gestureState);
  };

  const panResponder = useRef(
    PanResponder.create({
      onStartShouldSetPanResponder,
      onMoveShouldSetPanResponder,
      onPanResponderMove,
      onPanResponderRelease,
    }),
  ).current;

  useEffect(() => {
    scrollIsAtTopRef.current = scrollIsAtTop;
  }, [scrollIsAtTop]);

  useEffect(() => {
    const handleBackPress = () => {
      if (visible && onBackButtonPress) {
        onBackButtonPress();
        return true;
      }
      return false;
    };

    BackHandler.addEventListener('hardwareBackPress', handleBackPress);
  }, [visible, onBackButtonPress]);

  return {
    panResponder,
    translateY,
    visible,
    onScroll,
    scrollIsAtTop,
    onPanResponderMove,
    onPanResponderRelease,
  };
}

